<?php
const THIS_PAGE='external_videos';
require_once dirname(__FILE__,2).'/includes/admin_config.php';
require dirname(__FILE__,3).'/custom/external_videos/lib/external_videos_lib.php';
$msg='';$err='';
function ev_ids_from_post(): array { return array_values(array_filter(array_map('intval', $_POST['ids'] ?? []))); }
if($_SERVER['REQUEST_METHOD']==='POST'){
    $a=$_POST['action']??'';
    if($a==='import'){[$ok,$res]=ev_upsert(ev_import_metadata(trim($_POST['source_url']??''))); $ok?$msg='Imported pending ID '.$res:$err=$res;}
    if($a==='save'){[$ok,$res]=ev_upsert($_POST);$ok?$msg='Saved ID '.$res:$err=$res;}
    if($a==='publish'&&!empty($_POST['id'])){[$ok,$res]=ev_set_status((int)$_POST['id'],'published',$_POST['review_note']??'');$ok?$msg=$res:$err=$res;}
    if($a==='authorize'&&!empty($_POST['id'])){[$ok,$res]=ev_mark_authorized((int)$_POST['id'],$_POST['source_license']??'',$_POST['review_note']??'');$ok?$msg=$res:$err=$res;}
    if($a==='queue'&&!empty($_POST['id'])){[$ok,$res]=ev_queue_download((int)$_POST['id']);$ok?$msg=$res:$err=$res;}
    if($a==='reject'&&!empty($_POST['id'])){[$ok,$res]=ev_set_status((int)$_POST['id'],'rejected',$_POST['review_note']??'');$ok?$msg='Rejected':$err=$res;}
    if($a==='broken'&&!empty($_POST['id'])){[$ok,$res]=ev_set_status((int)$_POST['id'],'broken',$_POST['review_note']??'');$ok?$msg='Marked broken':$err=$res;}
    if($a==='bulk'&&ev_ids_from_post()){ $ids=ev_ids_from_post(); $bulk=$_POST['bulk_action']??''; $done=0;$errors=[]; foreach($ids as $id){ if($bulk==='publish')[$ok,$res]=ev_set_status($id,'published'); elseif($bulk==='reject')[$ok,$res]=ev_set_status($id,'rejected'); elseif($bulk==='broken')[$ok,$res]=ev_set_status($id,'broken'); elseif($bulk==='authorize')[$ok,$res]=ev_mark_authorized($id,'Bulk authorized: '.($_POST['bulk_note']??''),$_POST['bulk_note']??''); elseif($bulk==='queue')[$ok,$res]=ev_queue_download($id); else [$ok,$res]=[false,'Unknown bulk action']; $ok?$done++:$errors[]='ID '.$id.': '.$res; } $msg='Bulk processed '.$done.' item(s)'; if($errors)$err=implode("\n",$errors); }
    if($a==='delete'&&!empty($_POST['id'])){ev_db()->query('DELETE FROM cb_external_videos WHERE id='.(int)$_POST['id']);$msg='Deleted';}
}
$edit=null;if(!empty($_GET['edit']))$edit=ev_get((int)$_GET['edit']);
$items=ev_list(['q'=>$_GET['q']??'','status'=>$_GET['status']??'','provider'=>$_GET['provider']??'','download_status'=>$_GET['download_status']??'','limit'=>200]);
$statuses=['pending','published','rejected','broken','removed'];$dstats=['none','queued','downloading','downloaded','imported','failed'];
?><!doctype html><html><head><meta charset="utf-8"><title>External Videos Review</title><style>body{font-family:Arial;margin:24px;background:#f6f6f6}.box,table{background:#fff;border:1px solid #ddd}table{width:100%;border-collapse:collapse;font-size:13px}td,th{padding:8px;border:1px solid #ddd;text-align:left;vertical-align:top}.box{padding:16px;margin-bottom:16px}input,textarea,select{width:100%;box-sizing:border-box;margin:4px 0 10px;padding:8px}.btn{padding:8px 12px;background:#333;color:#fff;border:0;margin:2px;cursor:pointer}.btn.danger{background:#9b1c1c}.btn.ok{background:#176b36}.msg{background:#e6ffed;padding:10px;white-space:pre-wrap}.err{background:#ffecec;padding:10px;white-space:pre-wrap}.grid{display:grid;grid-template-columns:1fr 1fr;gap:16px}.thumb{width:120px;max-height:75px;object-fit:cover}iframe{width:420px;max-width:100%;aspect-ratio:16/9}.badge{display:inline-block;padding:2px 6px;border-radius:10px;background:#eee;margin:1px}.bad{background:#ffe0e0}.good{background:#dff7e8}.queued{background:#e1edff}.row-actions form{display:inline}.small{font-size:12px;color:#555}</style></head><body><h1>External Videos Review</h1><p><a href="/admin_area/">Admin Home</a> · <a href="/external_feed.php" target="_blank">Frontend Feed</a></p><?php if($msg):?><div class="msg"><?=ev_h($msg)?></div><?php endif;?><?php if($err):?><div class="err"><?=ev_h($err)?></div><?php endif;?><div class="grid"><div class="box"><h2>Import URL as pending metadata</h2><form method="post"><input type="hidden" name="action" value="import"><input name="source_url" required placeholder="https://www.youtube.com/watch?v=..."><button class="btn">Import as Pending</button></form><p class="small">Crawler/import only writes metadata: status=pending, authorized_download=false, download_status=none.</p></div><div class="box"><h2><?= $edit?'Edit / Review ID '.(int)$edit['id']:'Add External Video' ?></h2><form method="post"><input type="hidden" name="action" value="save"><input type="hidden" name="id" value="<?=ev_h($edit['id']??'')?>"><input name="title" required placeholder="Title" value="<?=ev_h($edit['title']??'')?>"><input name="slug" placeholder="Slug" value="<?=ev_h($edit['slug']??'')?>"><textarea name="description" placeholder="Description"><?=ev_h($edit['description']??'')?></textarea><input name="thumbnail_url" placeholder="Thumbnail URL" value="<?=ev_h($edit['thumbnail_url']??'')?>"><input name="source_url" required placeholder="Source URL" value="<?=ev_h($edit['source_url']??'')?>"><input name="embed_url" required placeholder="Embed URL" value="<?=ev_h($edit['embed_url']??'')?>"><input name="download_url" placeholder="Optional direct download URL (.mp4/.webm/.mov/.mkv only; discovered from detail page if blank)" value="<?=ev_h($edit['download_url']??'')?>"><input name="provider" placeholder="Provider" value="<?=ev_h($edit['provider']??'')?>"><input name="author" placeholder="Author" value="<?=ev_h($edit['author']??'')?>"><input name="duration" placeholder="Duration seconds" value="<?=ev_h($edit['duration']??'')?>"><input name="tags" placeholder="tags, comma, separated" value="<?=ev_h($edit['tags']??'')?>"><input name="category_id" placeholder="Category ID" value="<?=ev_h($edit['category_id']??'')?>"><select name="status"><?php foreach($statuses as $s):?><option value="<?=$s?>" <?=($edit['status']??'pending')===$s?'selected':''?>><?=$s?></option><?php endforeach;?></select><label><input type="checkbox" name="is_18_plus" value="1" <?=($edit['is_18_plus']??1)?'checked':''?> style="width:auto"> 18+</label><textarea name="source_license" placeholder="source_license / authorization note"><?=ev_h($edit['source_license']??'')?></textarea><textarea name="review_note" placeholder="review note"><?=ev_h($edit['review_note']??'')?></textarea><?php if($edit):?><p><span class="badge <?=((int)$edit['authorized_download']?'good':'bad')?>">authorized_download=<?=(int)$edit['authorized_download']?'true':'false'?></span> <span class="badge queued">download_status=<?=ev_h($edit['download_status']??'none')?></span><?php if(!empty($edit['download_url'])):?><br><span class="small">download_url: <?=ev_h($edit['download_url'])?></span><?php endif;?> <?php if(!empty($edit['clipbucket_video_id'])):?><a class="badge good" target="_blank" href="/watch_video.php?v=<?=(int)$edit['clipbucket_video_id']?>">ClipBucket #<?=(int)$edit['clipbucket_video_id']?></a><?php endif;?></p><?=ev_iframe($edit)?><p class="row-actions"><button class="btn">Save</button><button class="btn ok" form="publishForm">Publish external embed</button><button class="btn ok" form="authForm">Mark authorized</button><button class="btn ok" form="queueForm">Queue download</button><button class="btn danger" form="rejectForm">Reject</button><button class="btn danger" form="brokenForm">Mark broken</button></p><?php else:?><button class="btn">Save</button><?php endif;?></form><?php if($edit): foreach(['publish'=>'Publish external embed','authorize'=>'Mark authorized','queue'=>'Queue download','reject'=>'Reject','broken'=>'Mark broken'] as $act=>$label): ?><form id="<?=$act?>Form" method="post"><input type="hidden" name="action" value="<?=$act?>"><input type="hidden" name="id" value="<?=(int)$edit['id']?>"><input type="hidden" name="source_license" value="<?=ev_h($edit['source_license']??'')?>"><input type="hidden" name="review_note" value="<?=ev_h($edit['review_note']??'')?>"></form><?php endforeach; endif;?></div></div><form method="get" class="box"><input name="q" placeholder="search title, source, provider" value="<?=ev_h($_GET['q']??'')?>"><select name="status"><option value="">all status</option><?php foreach($statuses as $s):?><option value="<?=$s?>" <?=($_GET['status']??'')===$s?'selected':''?>><?=$s?></option><?php endforeach;?></select><select name="download_status"><option value="">all download status</option><?php foreach($dstats as $s):?><option value="<?=$s?>" <?=($_GET['download_status']??'')===$s?'selected':''?>><?=$s?></option><?php endforeach;?></select><input name="provider" placeholder="provider" value="<?=ev_h($_GET['provider']??'')?>"><button class="btn">Filter</button></form><form method="post"><input type="hidden" name="action" value="bulk"><select name="bulk_action"><option value="publish">bulk publish</option><option value="authorize">bulk mark authorized</option><option value="queue">bulk queue authorized downloads</option><option value="reject">bulk reject</option><option value="broken">bulk mark broken</option></select><input name="bulk_note" placeholder="bulk license/review note, required for meaningful authorization"><button class="btn">Run Bulk Action</button><table><tr><th></th><th>ID</th><th>Preview</th><th>Title</th><th>Status</th><th>Download</th><th>Provider/Source</th><th>License / Error</th><th>Actions</th></tr><?php foreach($items as $v):?><tr><td><input type="checkbox" name="ids[]" value="<?=$v['id']?>"></td><td><?=$v['id']?></td><td><?php if($v['thumbnail_url']):?><img class="thumb" src="<?=ev_h($v['thumbnail_url'])?>" alt=""><?php endif;?></td><td><?=ev_h($v['title'])?><br><span class="small"><?=ev_h($v['slug'])?></span></td><td><span class="badge"><?=ev_h($v['status'])?></span></td><td><span class="badge <?=((int)$v['authorized_download']?'good':'bad')?>">auth <?=((int)$v['authorized_download']?'yes':'no')?></span><br><span class="badge queued"><?=ev_h($v['download_status']??'none')?></span><?php if($v['clipbucket_video_id']):?><br><a target="_blank" href="/watch_video.php?v=<?=(int)$v['clipbucket_video_id']?>">native #<?=(int)$v['clipbucket_video_id']?></a><?php endif;?></td><td><?=ev_h($v['provider'])?><br><a target="_blank" href="<?=ev_h($v['source_url'])?>">source</a><?php if(!empty($v['download_url'])):?><br><a target="_blank" href="<?=ev_h($v['download_url'])?>">download_url</a><?php endif;?></td><td><?=ev_h(mb_substr(($v['download_error']?:($v['source_license']??$v['review_note']??'')),0,160))?></td><td class="row-actions"><a href="?edit=<?=$v['id']?>">edit/review</a> · <a target="_blank" href="/external_video.php?slug=<?=rawurlencode($v['slug'])?>">view</a></td></tr><?php endforeach;?></table></form></body></html>
